var surah076 = {
  number: 76,
  nameArabic: "al-Insan",
  nameEnglish: "Al-Insan",
  meaning: "Man",
  totalAyahs: 31,
  ayahs: [
    { number: 1, arabic: "هَلْ أَتَىٰ عَلَى ٱلْإِنسَٰنِ حِينٌۭ مِّنَ ٱلدَّهْرِ لَمْ يَكُن شَيْـًۭٔا مَّذْكُورًا", transliteration: "Hal ata AAala alinsani heenun mina alddahri lam yakun shayan mathkooran", transliterationB: "Hal ataa 'alal insaani heenum minad dahri lam yakun shai'am mazkooraa", english: "Has there not been over Man a long period of Time, when he was nothing - (not even) mentioned", romanUrdu: "Kya Insan par la mutanahi zamane ka ek waqt aisa bhi guzra hai jab woh koi qabil e zikr cheez na tha" },
    { number: 2, arabic: "إِنَّا خَلَقْنَا ٱلْإِنسَٰنَ مِن نُّطْفَةٍ أَمْشَاجٍۢ نَّبْتَلِيهِ فَجَعَلْنَٰهُ سَمِيعًۢا بَصِيرًا", transliteration: "Inna khalaqna alinsana min nutfatin amshajin nabtaleehi fajaAAalnahu sameeAAan baseeran", transliterationB: "Innaa khalaqnal insaana min nutfatin amshaajin nabta leehi faja'alnaahu samee'am baseeraa", english: "Verily We created Man from a drop of mingled sperm, in order to try him: So We gave him (the gifts), of Hearing and Sight", romanUrdu: "Humne Insan ko ek makhlut nutfey (intermingled sperm) se paida kiya taa-ke uska imtihaan lein aur is garz ke liye humne usey sunne aur dekhne wala banaya" },
    { number: 3, arabic: "إِنَّا هَدَيْنَٰهُ ٱلسَّبِيلَ إِمَّا شَاكِرًۭا وَإِمَّا كَفُورًا", transliteration: "Inna hadaynahu alssabeela imma shakiran waimma kafooran", transliterationB: "Innaa hadainaahus sabeela immaa shaakiranw wa immaa kafoora", english: "We showed him the Way: whether he be grateful or ungrateful (rests on his will)", romanUrdu: "Humne usey rasta dikha diya, khwa shukar karne wala baney ya kufr karne wala" },
    { number: 4, arabic: "إِنَّآ أَعْتَدْنَا لِلْكَٰفِرِينَ سَلَٰسِلَا۟ وَأَغْلَٰلًۭا وَسَعِيرًا", transliteration: "Inna aAAtadna lilkafireena salasila waaghlalan wasaAAeeran", transliterationB: "Innaaa a'tadnaa lilkaa fireena salaasila wa aghlaalanw wa sa'eeraa", english: "For the Rejecters we have prepared chains, yokes, and a blazing Fire", romanUrdu: "Kufr karne walon ke liye humne zanjeerein aur tauq (fetters) aur bhadakti hui aag muhaiyya kar rakkhi hai" },
    { number: 5, arabic: "إِنَّ ٱلْأَبْرَارَ يَشْرَبُونَ مِن كَأْسٍۢ كَانَ مِزَاجُهَا كَافُورًا", transliteration: "Inna alabrara yashraboona min kasin kana mizajuha kafooran", transliterationB: "innal abraara yashra boona min kaasin kaana mizaa juhaa kaafooraa", english: "As to the Righteous, they shall drink of a Cup (of Wine) mixed with Kafur", romanUrdu: "Neik log (jannat mein) sharaab ke aisey sagar piyenge jinmein aabey kafoor ki aamezish (mixture) hogi" },
    { number: 6, arabic: "عَيْنًۭا يَشْرَبُ بِهَا عِبَادُ ٱللَّهِ يُفَجِّرُونَهَا تَفْجِيرًۭا", transliteration: "AAaynan yashrabu biha AAibadu Allahi yufajjiroonaha tafjeeran", transliterationB: "Aynany yashrabu bihaa 'ibaadul laahi yafajjiroonahaa tafjeeraa", english: "A Fountain where the Devotees of Allah do drink, making it flow in unstinted abundance", romanUrdu: "Yeh ek behta chasma(spring) hoga jiske pani ke saath Allah ke bandey sharaab piyengey aur jahan chahengey ba-sahulat uski shakhein (nikal) lengey" },
    { number: 7, arabic: "يُوفُونَ بِٱلنَّذْرِ وَيَخَافُونَ يَوْمًۭا كَانَ شَرُّهُۥ مُسْتَطِيرًۭا", transliteration: "Yoofoona bialnnathri wayakhafoona yawman kana sharruhu mustateeran", transliterationB: "Yoofoona binnazri wa yakhaafoona yawman kaana sharruhoo mustateeraa", english: "They perform (their) vows, and they fear a Day whose evil flies far and wide", romanUrdu: "Yeh woh log hongey jo (duniya mein) nazar poori karte hain, aur us din se darte hain jiski aafat har taraf phaili hui hogi" },
    { number: 8, arabic: "وَيُطْعِمُونَ ٱلطَّعَامَ عَلَىٰ حُبِّهِۦ مِسْكِينًۭا وَيَتِيمًۭا وَأَسِيرًا", transliteration: "WayutAAimona alttaAAama AAala hubbihi miskeenan wayateeman waaseeran", transliterationB: "Wa yut''imoonat ta'aama 'alaa hubbihee miskeenanw wa yatemanw wa aseeraa", english: "And they feed, for the love of Allah, the indigent, the orphan, and the captive", romanUrdu: "Aur Allah ki muhabbat mein miskeen aur yateem aur qaidi ko khana khilate hain" },
    { number: 9, arabic: "إِنَّمَا نُطْعِمُكُمْ لِوَجْهِ ٱللَّهِ لَا نُرِيدُ مِنكُمْ جَزَآءًۭ وَلَا شُكُورًا", transliteration: "Innama nutAAimukum liwajhi Allahi la nureedu minkum jazaan wala shukooran", transliterationB: "Innaamaa nut'imukum li wajhil laahi laa nureedu minkum jazaaa'anw wa laa shukooraa", english: "(Saying),\"We feed you for the sake of Allah alone: no reward do we desire from you, nor thanks", romanUrdu: "Aur unse kehte hain ke (hum tumhein sirf) Allah ki khatir khila rahey hain, hum tumse na koi badla chahte hain na shukriya" },
    { number: 10, arabic: "إِنَّا نَخَافُ مِن رَّبِّنَا يَوْمًا عَبُوسًۭا قَمْطَرِيرًۭا", transliteration: "Inna nakhafu min rabbina yawman AAaboosan qamtareeran", transliterationB: "Innaa nakhaafu mir Rabbinna Yawman 'aboosan qamtareeraa", english: "We only fear a Day of distressful Wrath from the side of our Lord", romanUrdu: "Humey to apne Rubb se us din ke azaab ka khauf lahiq hai jo sakht museebat ka intehayi taweel din hoga" },
    { number: 11, arabic: "فَوَقَىٰهُمُ ٱللَّهُ شَرَّ ذَٰلِكَ ٱلْيَوْمِ وَلَقَّىٰهُمْ نَضْرَةًۭ وَسُرُورًۭا", transliteration: "Fawaqahumu Allahu sharra thalika alyawmi walaqqahum nadratan wasurooran", transliterationB: "Fa waqaahumul laahu sharra zaalikal yawmi wa laqqaahum nadratanw wa surooraa", english: "But Allah will deliver them from the evil of that Day, and will shed over them a Light of Beauty and (blissful) Joy", romanUrdu: "Pas Allah taala unhein us din ke sharr se bacha lega aur unhein taazgi aur suroor bakshega" },
    { number: 12, arabic: "وَجَزَىٰهُم بِمَا صَبَرُوا۟ جَنَّةًۭ وَحَرِيرًۭا", transliteration: "Wajazahum bima sabaroo jannatan wahareeran", transliterationB: "Wa jazaahum bimaa sabaroo janatanw wa hareeraa", english: "And because they were patient and constant, He will reward them with a Garden and (garments of) silk", romanUrdu: "Aur unke sabr ke badle mein unhein jannat aur reshmi libas ata karega" },
    { number: 13, arabic: "مُّتَّكِـِٔينَ فِيهَا عَلَى ٱلْأَرَآئِكِ ۖ لَا يَرَوْنَ فِيهَا شَمْسًۭا وَلَا زَمْهَرِيرًۭا", transliteration: "Muttakieena feeha AAala alaraiki la yarawna feeha shamsan wala zamhareeran", transliterationB: "muttaki'eena feeha 'alal araaa 'iki laa yarawna feehaa shamsanw wa laa zamhareeraa", english: "Reclining in the (Garden) on raised thrones, they will see there neither the sun's (excessive heat) nor (the moon's) excessive cold", romanUrdu: "Wahan woh unchey masnadon par takiye lagaye baithey hongey, na unhein dhoop ki garmi satayegi na jaadey ki thirr (bitter cold)" },
    { number: 14, arabic: "وَدَانِيَةً عَلَيْهِمْ ظِلَٰلُهَا وَذُلِّلَتْ قُطُوفُهَا تَذْلِيلًۭا", transliteration: "Wadaniyatan AAalayhim thilaluha wathullilat qutoofuha tathleelan", transliterationB: "Wa daaniyatan 'alaihim zilaaluhaa wa zullilat qutoofu haa tazleela", english: "And the shades of the (Garden) will come low over them, and the bunches (of fruit), there, will hang low in humility", romanUrdu: "Jannat ki chaaon unpar jhuki hui saaya kar rahi hogi,aur uske phal har waqt unke bas mein hongey(ke jis tarah chahey unhein todh lein)" },
    { number: 15, arabic: "وَيُطَافُ عَلَيْهِم بِـَٔانِيَةٍۢ مِّن فِضَّةٍۢ وَأَكْوَابٍۢ كَانَتْ قَوَارِيرَا۠", transliteration: "Wayutafu AAalayhim bianiyatin min fiddatin waakwabin kanat qawareera", transliterationB: "Wa yutaafu 'alaihim bi aaniyatim min fiddatinw wa akwaabin kaanat qawaareeraa", english: "And amongst them will be passed round vessels of silver and goblets of crystal", romanUrdu: "Unke aagey chandi ke bartan aur sheshey ke pyale gardish karaye ja rahey hongey" },
    { number: 16, arabic: "قَوَارِيرَا۟ مِن فِضَّةٍۢ قَدَّرُوهَا تَقْدِيرًۭا", transliteration: "Qawareera min fiddatin qaddarooha taqdeeran", transliterationB: "Qawaareera min fiddatin qaddaroohaa taqdeeraa", english: "Crystal-clear, made of silver: they will determine the measure thereof (according to their wishes)", romanUrdu: "Sheshey bhi woh jo chandi ki qisam ke hongey,aur unko (muntazmin-e-jannat nay)theek andazey ke mutabik bhara hoga" },
    { number: 17, arabic: "وَيُسْقَوْنَ فِيهَا كَأْسًۭا كَانَ مِزَاجُهَا زَنجَبِيلًا", transliteration: "Wayusqawna feeha kasan kana mizajuha zanjabeelan", transliterationB: "Wa yusawna feehaa kaasan kaana mizaajuhaa zanjabeelaa", english: "And they will be given to drink there of a Cup (of Wine) mixed with Zanjabil", romanUrdu: "Unko wahan aisi sharaab ke jaam pilaye jayenge jis mein soont (ginger) ki aamezish hogi" },
    { number: 18, arabic: "عَيْنًۭا فِيهَا تُسَمَّىٰ سَلْسَبِيلًۭا", transliteration: "AAaynan feeha tusamma salsabeelan", transliterationB: "Aynan feeha tusammaa salsabeelaa", english: "A fountain there, called Salsabil", romanUrdu: "Yeh jannat ka ek chasma hoga jisey salsabil kaha jata hai" },
    { number: 19, arabic: "۞ وَيَطُوفُ عَلَيْهِمْ وِلْدَٰنٌۭ مُّخَلَّدُونَ إِذَا رَأَيْتَهُمْ حَسِبْتَهُمْ لُؤْلُؤًۭا مَّنثُورًۭا", transliteration: "Wayatoofu AAalayhim wildanun mukhalladoona itha raaytahum hasibtahum luluan manthooran", transliterationB: "Wa yatoofu 'alaihim wildaanum mukhalladoona izaa ra aytahum hasibtahum lu'lu 'am mansoora", english: "And round about them will (serve) youths of perpetual (freshness): If thou seest them, thou wouldst think them scattered Pearls", romanUrdu: "Unki khidmat ke liye aisey ladke daudte phir rahey hongey jo hamesha ladke hi rahenge.Tum unhein dekho to samjho ke moti(pearls) hai jo bikhair diye gaye hain" },
    { number: 20, arabic: "وَإِذَا رَأَيْتَ ثَمَّ رَأَيْتَ نَعِيمًۭا وَمُلْكًۭا كَبِيرًا", transliteration: "Waitha raayta thamma raayta naAAeeman wamulkan kabeeran", transliterationB: "Wa izaa ra ayta summa ra ayta na'eemanw wa mulkan kabeera", english: "And when thou lookest, it is there thou wilt see a Bliss and a Realm Magnificent", romanUrdu: "Wahan jidhar bhi tum nigah dalogey niyamatein hi niyamatein aur ek badi sultanat ka sar o saman tumhein nazar aayega" },
    { number: 21, arabic: "عَٰلِيَهُمْ ثِيَابُ سُندُسٍ خُضْرٌۭ وَإِسْتَبْرَقٌۭ ۖ وَحُلُّوٓا۟ أَسَاوِرَ مِن فِضَّةٍۢ وَسَقَىٰهُمْ رَبُّهُمْ شَرَابًۭا طَهُورًا", transliteration: "AAaliyahum thiyabu sundusin khudrun waistabraqun wahulloo asawira min fiddatin wasaqahum rabbuhum sharaban tahooran", transliterationB: "Aaliyahum siyaabu sundusin khudrunw wa istabraq, wa hullooo asaawira min fiddatinw wa saqaahum Rabbuhum sharaaban tahooraa", english: "Upon them will be green Garments of fine silk and heavy brocade, and they will be adorned with Bracelets of silver; and their Lord will give to them to drink of a Wine Pure and Holy", romanUrdu: "Unke upar bareek resham ke sabz libas aur atlas o deba ke kapde (rich brocade)hongey, unko chandi ke kangan pehnaye jayenge , aur unka Rubb unko nihayat pakeeza sharaab pilaeyga" },
    { number: 22, arabic: "إِنَّ هَٰذَا كَانَ لَكُمْ جَزَآءًۭ وَكَانَ سَعْيُكُم مَّشْكُورًا", transliteration: "Inna hatha kana lakum jazaan wakana saAAyukum mashkooran", transliterationB: "Innaa haazaa kaana lakum jazz 'anw wa kaana sa'yukum mashkooraa", english: "Verily this is a Reward for you, and your Endeavour is accepted and recognised", romanUrdu: "Yeh hai tumhari jaza aur tumhari kaar-guzari qabil-e-qadr thehri hai" },
    { number: 23, arabic: "إِنَّا نَحْنُ نَزَّلْنَا عَلَيْكَ ٱلْقُرْءَانَ تَنزِيلًۭا", transliteration: "Inna nahnu nazzalna AAalayka alqurana tanzeelan", transliterationB: "Innaa nahnu nazzalnaa 'alaikal quraana tanzeelaa", english: "It is We Who have sent down the Qur'an to thee by stages", romanUrdu: "Aey Nabi, humne hi tumpar yeh Quran thoda thoda karke nazil kiya hai" },
    { number: 24, arabic: "فَٱصْبِرْ لِحُكْمِ رَبِّكَ وَلَا تُطِعْ مِنْهُمْ ءَاثِمًا أَوْ كَفُورًۭا", transliteration: "Faisbir lihukmi rabbika wala tutiAA minhum athiman aw kafooran", transliterationB: "Fasbir lihukmi Rabbika wa laa tuti' minhum aasiman aw kafooraa", english: "Therefore be patient with constancy to the Command of thy Lord, and hearken not to the sinner or the ingrate among them", romanUrdu: "Lihaza tum apne Rubb ke hukum par sabr karo, aur in mein se kisi badh-amal ya munkir-e-haq ki baat na maano" },
    { number: 25, arabic: "وَٱذْكُرِ ٱسْمَ رَبِّكَ بُكْرَةًۭ وَأَصِيلًۭا", transliteration: "Waothkuri isma rabbika bukratan waaseelan", transliterationB: "Wazkuris ma Rabbika bukratanw wa aseelaa", english: "And celebrate the name of thy Lord morning and evening", romanUrdu: "Apne Rubb ka naam subh-o-shaam yaad karo" },
    { number: 26, arabic: "وَمِنَ ٱلَّيْلِ فَٱسْجُدْ لَهُۥ وَسَبِّحْهُ لَيْلًۭا طَوِيلًا", transliteration: "Wamina allayli faosjud lahu wasabbihhu laylan taweelan", transliterationB: "Wa minal laili fasjud lahoo wa sabbihhu lailan taweelaa", english: "And part of the night, prostrate thyself to Him; and glorify Him a long night through", romanUrdu: "Raat ko bhi uske huzoor sajda raiz ho, Aur raat ke taveel auqat mein uski tasbeeh karte raho" },
    { number: 27, arabic: "إِنَّ هَٰٓؤُلَآءِ يُحِبُّونَ ٱلْعَاجِلَةَ وَيَذَرُونَ وَرَآءَهُمْ يَوْمًۭا ثَقِيلًۭا", transliteration: "Inna haolai yuhibboona alAAajilata wayatharoona waraahum yawman thaqeelan", transliterationB: "Inna haaa'ulaa'i yuhibboona 'aajilata wa yazaroona waraaa'ahum yawman saqeelaa", english: "As to these, they love the fleeting life, and put away behind them a Day (that will be) hard", romanUrdu: "Yeh log to jaldi hasil honay wali cheez (duniya ) se muhabbat rakhte hai aur aagey jo bhaari din aane wala hai usey nazar andaz kardetey hain" },
    { number: 28, arabic: "نَّحْنُ خَلَقْنَٰهُمْ وَشَدَدْنَآ أَسْرَهُمْ ۖ وَإِذَا شِئْنَا بَدَّلْنَآ أَمْثَٰلَهُمْ تَبْدِيلًا", transliteration: "Nahnu khalaqnahum washadadna asrahum waitha shina baddalna amthalahum tabdeelan", transliterationB: "Nahnu khalaqnaahum wa shadadnaaa asrahum wa izaa shi'naa baddalnaaa amsaala hum tabdeelaa", english: "It is We Who created them, and We have made their joints strong; but, when We will, We can substitute the like of them by a complete change", romanUrdu: "Humne hi inko paida kiya hai aur inke jodh bandh mazboot kiye hai, aur hum jab chahein inki shakalon ko badal kar rakh dein" },
    { number: 29, arabic: "إِنَّ هَٰذِهِۦ تَذْكِرَةٌۭ ۖ فَمَن شَآءَ ٱتَّخَذَ إِلَىٰ رَبِّهِۦ سَبِيلًۭا", transliteration: "Inna hathihi tathkiratun faman shaa ittakhatha ila rabbihi sabeelan", transliterationB: "Inna haazihee tazkiratun fa man shaaa'at takhaza ilaa rabbihee sabeela", english: "This is an admonition: Whosoever will, let him take a (straight) Path to his Lord", romanUrdu: "Yeh ek nasihat hai,ab jiska jee chahey apne Rubb ki taraf jaane ka rasta ikhtiyar karle" },
    { number: 30, arabic: "وَمَا تَشَآءُونَ إِلَّآ أَن يَشَآءَ ٱللَّهُ ۚ إِنَّ ٱللَّهَ كَانَ عَلِيمًا حَكِيمًۭا", transliteration: "Wama tashaoona illa an yashaa Allahu inna Allaha kana AAaleeman hakeeman", transliterationB: "Wa maa tashaaa'oona illaa anyyashaaa'al laah; innal laahaa kaana'Aleeman Hakeema", english: "But ye will not, except as Allah wills; for Allah is full of Knowledge and Wisdom", romanUrdu: "Aur tumharey chahne se kuch nahin hota jab tak ke Allah na chachey, yaqeenan Allah bada Aleem-o-Haqeem hai" },
    { number: 31, arabic: "يُدْخِلُ مَن يَشَآءُ فِى رَحْمَتِهِۦ ۚ وَٱلظَّٰلِمِينَ أَعَدَّ لَهُمْ عَذَابًا أَلِيمًۢا", transliteration: "Yudkhilu man yashao fee rahmatihi waalththalimeena aAAadda lahum AAathaban aleeman", transliterationB: "Yudkhilu mai yashaaa'u fee rahmatih; wazzaalimeena a'adda lahum 'azaaban aleemaa", english: "He will admit to His Mercy whom He will; But the wrong-doers,- for them has He prepared a grievous Penalty", romanUrdu: "Apni rehmat mein jisko chahta hai daakhil karta hai, Aur zalimon ke liye usne dardnaak azaab tayyar kar rakkha hai" }
  ]
};
